// Deep Link Handler Singleton
class DeepLinkHandler {
  static final GlobalKey<NavigatorState> navigatorKey =
      GlobalKey<NavigatorState>();

  static StreamSubscription? _linkSubscription;
  static bool _initialLinkHandled = false;

  static Future<void> init() async {
    // Handle initial deep link (app was closed)
    if (!_initialLinkHandled) {
      _initialLinkHandled = true;
      try {
        final initialLink = await getInitialLink();
        if (initialLink != null) {
          _handleDeepLink(initialLink);
        }
      } catch (e) {
        debugPrint('Error getting initial link: $e');
      }
    }

    // Handle deep links while app is running
    _linkSubscription?.cancel();
    _linkSubscription = linkStream.listen(
      (String? link) {
        if (link != null) {
          _handleDeepLink(link);
        }
      },
      onError: (err) {
        debugPrint('Deep link stream error: $err');
      },
    );
  }

  static void dispose() {
    _linkSubscription?.cancel();
    _linkSubscription = null;
  }

  static void _handleDeepLink(String link) {
    debugPrint('Received deep link: $link');

    final parsedRoute = DeepLinkParser.parse(link);
    if (parsedRoute != null) {
      navigatorKey.currentState?.pushNamed(
        parsedRoute.routeName,
        arguments: parsedRoute.parameters,
      );
    } else {
      debugPrint('Unknown deep link: $link');
    }
  }
}

// Parsed Route Model
class ParsedRoute {
  final String routeName;
  final Map<String, dynamic> parameters;

  const ParsedRoute({
    required this.routeName,
    required this.parameters,
  });

  @override
  String toString() =>
      'ParsedRoute(routeName: $routeName, parameters: $parameters)';
}

// Deep Link Parser
class DeepLinkParser {
  static const String scheme = 'myapp';

  static ParsedRoute? parse(String link) {
    try {
      final uri = Uri.parse(link);

      if (uri.scheme != scheme) {
        debugPrint('Unknown scheme: ${uri.scheme}');
        return null;
      }

      final host = uri.host;
      final pathSegments =
          uri.pathSegments.where((s) => s.isNotEmpty).toList();
      final queryParams = uri.queryParameters;

      switch (host) {
        case 'profile':
          return _parseProfileLink(pathSegments, queryParams);
        case 'payment':
          return _parsePaymentLink(pathSegments, queryParams);
        case 'product':
          return _parseProductLink(pathSegments, queryParams);
        case 'campaign':
          return _parseCampaignLink(pathSegments, queryParams);
        case 'notification':
          return _parseNotificationLink(pathSegments, queryParams);
        default:
          debugPrint('Unknown host: $host');
          return null;
      }
    } catch (e) {
      debugPrint('Error parsing deep link: $e');
      return null;
    }
  }

  // myapp://profile/123
  // myapp://profile/123?tab=posts
  static ParsedRoute? _parseProfileLink(
      List<String> pathSegments, Map<String, String> queryParams) {
    if (pathSegments.isEmpty) {
      return const ParsedRoute(
        routeName: '/profile',
        parameters: {},
      );
    }

    final userId = pathSegments[0];
    return ParsedRoute(
      routeName: '/profile',
      parameters: {
        'userId': userId,
        'tab': queryParams['tab'] ?? 'info',
        ...queryParams,
      },
    );
  }

  // myapp://payment/confirm
  // myapp://payment/confirm?orderId=456&amount=29.99
  // myapp://payment/history
  static ParsedRoute? _parsePaymentLink(
      List<String> pathSegments, Map<String, String> queryParams) {
    if (pathSegments.isEmpty) {
      return const ParsedRoute(
        routeName: '/payment',
        parameters: {},
      );
    }

    final action = pathSegments[0];
    switch (action) {
      case 'confirm':
        return ParsedRoute(
          routeName: '/payment/confirm',
          parameters: {
            'orderId': queryParams['orderId'] ?? '',
            'amount': double.tryParse(queryParams['amount'] ?? '') ?? 0.0,
            'currency': queryParams['currency'] ?? 'USD',
            ...queryParams,
          },
        );
      case 'history':
        return ParsedRoute(
          routeName: '/payment/history',
          parameters: {...queryParams},
        );
      default:
        return ParsedRoute(
          routeName: '/payment',
          parameters: {'action': action, ...queryParams},
        );
    }
  }

  // myapp://product/789?ref=campaign_summer
  static ParsedRoute? _parseProductLink(
      List<String> pathSegments, Map<String, String> queryParams) {
    if (pathSegments.isEmpty) return null;

    final productId = pathSegments[0];
    return ParsedRoute(
      routeName: '/product',
      parameters: {
        'productId': productId,
        'ref': queryParams['ref'] ?? 'direct',
        ...queryParams,
      },
    );
  }

  // myapp://campaign/summer_sale?discount=20&code=SUMMER20
  static ParsedRoute? _parseCampaignLink(
      List<String> pathSegments, Map<String, String> queryParams) {
    if (pathSegments.isEmpty) return null;

    final campaignId = pathSegments[0];
    return ParsedRoute(
      routeName: '/campaign',
      parameters: {
        'campaignId': campaignId,
        'discount': queryParams['discount'] ?? '0',
        'code': queryParams['code'] ?? '',
        ...queryParams,
      },
    );
  }

  // myapp://notification/message?id=notif_001&type=promo
  static ParsedRoute? _parseNotificationLink(
      List<String> pathSegments, Map<String, String> queryParams) {
    final type = pathSegments.isNotEmpty ? pathSegments[0] : 'general';
    return ParsedRoute(
      routeName: '/notification',
      parameters: {
        'type': type,
        'notificationId': queryParams['id'] ?? '',
        ...queryParams,
      },
    );
  }
}

// App Router
class AppRouter {
  static Route<dynamic> generateRoute(RouteSettings settings) {
    final args = settings.arguments as Map<String, dynamic>? ?? {};

    switch (settings.name) {
      case '/profile':
        return MaterialPageRoute(
          builder: (_) => ProfileScreen(
            userId: args['userId'] as String? ?? '',
            tab: args['tab'] as String? ?? 'info',
          ),
          settings: settings,
        );

      case '/payment/confirm':
        return MaterialPageRoute(
          builder: (_) => PaymentConfirmScreen(
            orderId: args['orderId'] as String? ?? '',
            amount: (args['amount'] is double)
                ? args['amount'] as double
                : double.tryParse(args['amount']?.toString() ?? '') ?? 0.0,
            currency: args['currency'] as String? ?? 'USD',
          ),
          settings: settings,
        );

      case '/payment/history':
        return MaterialPageRoute(
          builder: (_) => const PaymentHistoryScreen(),
          settings: settings,
        );

      case '/payment':
        return MaterialPageRoute(
          builder: (_) => PaymentScreen(parameters: args),
          settings: settings,
        );

      case '/product':
        return MaterialPageRoute(
          builder: (_) => ProductScreen(
            productId: args['productId'] as String? ?? '',
            ref: args['ref'] as String? ?? 'direct',
          ),
          settings: settings,
        );

      case '/campaign':
        return MaterialPageRoute(
          builder: (_) => CampaignScreen(
            campaignId: args['campaignId'] as String? ?? '',
            discount: args['discount'] as String? ?? '0',
            code: args['code'] as String? ?? '',
          ),
          settings: settings,
        );

      case '/notification':
        return MaterialPageRoute(
          builder: (_) => NotificationScreen(
            type: args['type'] as String? ?? 'general',
            notificationId: args['notificationId'] as String? ?? '',
          ),
          settings: settings,
        );

      default:
        return MaterialPageRoute(
          builder: (_) => const UnknownRouteScreen(),
          settings: settings,
        );
    }
  }
}

